def compute_score() -> tuple[str, float]:
    from ppteval.verify.ppt.verifier import ScreenshotsUnavailableError
    # Use VLM to check whether both specified bullet points are present on slide 5
    # Find slide 5 screenshot (supports object with attributes or dict with keys)
    slide_5_image = None

    if len(ppt_diff.modified_slides) + len(ppt_diff.added_slides) == 0:
        return 'No modifications detected on slide 5.', 0.0

    for s in modified_ppt_screenshots:
        try:
            s_num = getattr(s, 'slide_number', None)
            if s_num is None and isinstance(s, dict):
                s_num = s.get('slide_number')
            if s_num == 5:
                slide_5_image = s.image_path
                break
        except Exception:
            continue
    if not slide_5_image:
        # Infra-vs-model disambiguation: if slide exists in modified pptx,
        # the missing screenshot is an infra failure (raise to retry).
        from pptx import Presentation as _Pres
        try:
            _slide_count = len(_Pres(modified_ppt_path).slides)
        except Exception:
            _slide_count = 0
        if _slide_count >= 5:
            raise ScreenshotsUnavailableError("Slide 5 screenshot not found; flagging task for verification retry.")
        return 'Slide 5 screenshot not found.', 0.0

    prompt = (
        "Look at this PowerPoint slide (slide 5) and read the bullet points.\n"
        "We expect exactly these two bullet sentences to appear as bullets:\n"
        "1) 'Early Life: A child's risk of becoming obese may begin before birth'\n"
        "2) 'Pregnant women who use tobacco, gain excessive weight, or have diabetes increase their children's obesity risk'\n"
        "Do both of these exact bullet sentences appear on the slide (ignore indentation issues)? Respond with:\n"
        "- YES if both appear,\n"
        "- PARTIAL if only one appears,\n"
        "- NONE if neither appears.\n"
        "Include a brief justification after the above response."
    )

    try:
        response = vlm_call(images=[slide_5_image], prompt=prompt, temperature=0.1, max_tokens=200)
        resp = str(response).strip()
        if 'YES' in resp and 'PARTIAL' not in resp and 'NONE' not in resp:
            return response, 1.0
        elif 'PARTIAL' in resp or ('YES' in resp and 'NO' in resp):
            return response, 0.5
        elif 'NONE' in resp or 'NO' in resp:
            return response, 0.0
        else:
            return f'Unclear response from VLM: {response}', 0.0
    except Exception as e:
        return f'Error during VLM check: {str(e)}', 0.0

def compute_score():
    # Check for modifications to slide 5 other than bullet/text changes
    extraneous = False
    for s1, s2 in ppt_diff.modified_slides:
        if s1.slide_number == 5 or s2.slide_number == 5:
            # Compare layout_type, notes, element_count
            # Ignore title, since that's often the paragraph.
            if (s1.layout_type != s2.layout_type) or (s1.notes != s2.notes) or (s1.element_count != s2.element_count):
                extraneous = True
    if extraneous:
        return 'Extraneous changes detected on slide 5.', 0.0
    return 'No extraneous changes detected on slide 5.', 1.0
